sys_script.script:
(function executeRule(current, previous /*null when async*/) {

    var fiscalYearId = current.sys_id;

    // -------------------------------
    // 1. Check ACTIVE QUOTAS linked directly to Fiscal Year
    // -------------------------------
    var quotaGR = new GlideRecord('x_ctans_incentnow_quota'); 
    quotaGR.addQuery('fiscal_year', fiscalYearId); 
    quotaGR.addQuery('status','!=', 'inactive');
    quotaGR.setLimit(1);
    quotaGR.query();

    if (quotaGR.hasNext()) {
        gs.addErrorMessage('Cannot deactivate Fiscal Year: Active Quotas are associated.');
        current.setAbortAction(true);
        return;
    }

    // -------------------------------
    // 2. Check ACTIVE PLANS via Fiscal Period
    // Plan -> Fiscal Period -> Fiscal Year
    // -------------------------------
    var periodGR = new GlideRecord('x_ctans_incentnow_fiscal_period'); 
    periodGR.addQuery('fiscal_year', fiscalYearId);
    periodGR.query();

    var periodIds = [];
    while (periodGR.next()) {
        periodIds.push(periodGR.sys_id.toString());
    }

    if (periodIds.length > 0) {
        var planGR = new GlideRecord('x_ctans_incentnow_plan');
        planGR.addQuery('fiscal_period', 'IN', periodIds); 
        planGR.addQuery('status','!=', 'inactive');
        planGR.setLimit(1);
        planGR.query();

        if (planGR.hasNext()) {
            gs.addErrorMessage('Cannot deactivate Fiscal Year: Active Plans are associated via Fiscal Periods.');
            current.setAbortAction(true);
            return;
        }
    }

})(current, previous);
